//   name: stringSchema(),
//   phone: stringSchema(),
//   skin_color: stringSchema(),
//   surname: stringSchema(),
// })

type Statistics = InferType<typeof statisticsSchema>;
const statisticsSchema = objectSchema({
  total_customers: numberSchema(),
  total_analysis: numberSchema(),
  total_registered_devices: numberSchema(),
  total_consultants: numberSchema(),
  total_stores: numberSchema(),

});

type StoreDetailsStatistics = InferType<typeof storeDetailsSchema>;
const storeDetailsSchema = objectSchema({
  month: stringSchema(),
  total_analysis: numberSchema(),
  total_consultants: numberSchema(),
  total_customers: numberSchema(),
  number_of_devices: numberSchema(),
  store_email: stringSchema(),
  store_id: numberSchema(),
  store_name: stringSchema(),
  store_phone: stringSchema(),
  total_new_analysis_this_month: numberSchema(),
  total_new_analysis_this_week: numberSchema(),
  total_new_customers_this_month: numberSchema(),
  total_new_customers_this_week: numberSchema(),
  week: objectSchema({
    from: stringSchema(),
    to: stringSchema(),
  }),
});

type AnalysisHistory = InferType<typeof analysisHistorySchema>;
const analysisHistorySchema = objectSchema({
  branch_name: stringSchema(),
  total_analysis: numberSchema(),
  total_consultants: numberSchema(),
  total_customers: numberSchema(),
  total_stores: numberSchema(),
  store_id: numberSchema(),
  store_name: stringSchema(),
  total_registered_devices: numberSchema()
});

const today = new Date();
// eslint-disable-next-line @typescript-eslint/naming-convention
const start_of_month = startOfMonth(today);

export function StatisticsAndReports(props: any) {
  const { t } = useTranslation();
  const api = useAPI();
  const statistics = useRequest<Statistics>(() =>
    api.requestResource('/api/partnerdb/statistics')
  );
  const { data: companyInfo } = useRequest<{ data: CompanyInfo }>(() =>
    api.requestResource('/api/partnerdb/companies/me')
  );

  const { store_id } = useParams<{ store_id: string }>();
  const [dateRange1, setDateRange1] = useState<{ from: Date; to: Date }>({
    from: start_of_month,
    to: today,
  });
  const [dateRange2, setDateRange2] = useState<{ from: Date; to: Date }>({
    from: start_of_month,
    to: today,
  });

  // const storeDetailsStatistics = useRequest<StoreDetailsStatistics>(() =>
  //   api.requestResource(`/statistics/reports/${store_id}/store-details/`)
  // );

  // const totalCustomers = useHttpResource<{ number_of_customers: number }>(
  //   `/statistics/reports/${store_id}/store-details/total_customers/`,
  //   {
  //     from: format(dateRange1.from, 'yyyyMMdd'),
  //     to: format(dateRange1.to, 'yyyyMMdd'),
  //   },
  //   {
  //     pagination: false,
  //     shouldFetch: !!store_id,
  //   }
  // );

  // const totalAnalysis = useHttpResource<{ 'count(temp.batch_id)': number }>(
  //   `/statistics/reports/${store_id}/store-details/total_analysis/`,
  //   {
  //     from: format(dateRange2.from, 'yyyyMMdd'),
  //     to: format(dateRange2.to, 'yyyyMMdd'),
  //   },
  //   {
  //     pagination: false,
  //     shouldFetch: !!store_id,
  //   }
  // );

  return (
    <Layout title={t('statistics.title')}>
      {/* <TableContainer component={Paper} variant="outlined">
        <Table>
          <TableBody >
            <TableRow >
              <TableCell>
                <Typography gutterBottom>{t('brand_details.company')}</Typography>
                <Typography>
                  <b>{companyInfo?.data?.name} </b>
                </Typography>
              </TableCell>
            </TableRow>
            <TableRow>
              <TableCell>
                <Typography gutterBottom>{t('brand_details.address')}</Typography>
                <Typography>
                  <b>{companyInfo?.data?.address} </b>
                </Typography>
              </TableCell>
            </TableRow>
              <TableRow>
                <TableCell>
                  <Typography gutterBottom>{t('brand_details.contact_information')}</Typography>
                  <Typography>
                    <b>{companyInfo?.data?.email || companyInfo?.data?.phone} </b>
                  </Typography>
                </TableCell>
              </TableRow>
              <TableRow>
                <TableCell>
                  <Typography gutterBottom>{t('brand_details.started_since')}</Typography>
                  <Typography>
                    <b>{parseDateString(companyInfo?.data?.registration_date || '')} </b>
                  </Typography>
                </TableCell>
              </TableRow>
          </TableBody>
        </Table>
      </TableContainer> */}

      {/* <Box paddingY={2}>
        <Paper variant="outlined">
          <Box padding={2}>
            <Grid container spacing={2}>
              <Grid item sm>
                <Typography>
                  <b>{t('statistics.total_customers')}</b>
                  <Divider />
                </Typography>
                <Typography>
                  <b>{t('statistics.overall')}:</b> {statistics.data?.total_customers}
                </Typography>
              </Grid>
              <Grid item sm>
                <Typography>
                  <b>{t('statistics.total_devices_overall')}</b>
                  <Divider />
                </Typography>
                <Typography>
                  <b>{t('statistics.overall')}:</b> {statistics.data?.total_registered_devices}
                </Typography>
              </Grid>
              <Grid item sm>
                <Typography>
                  <b>{t('statistics.total_analysis')}</b>
                  <Divider />
                </Typography>
                <Typography>
                  <b>{t('statistics.overall')}:</b> {statistics.data?.total_analysis}
                </Typography>
              </Grid>
            </Grid>
          </Box>
        </Paper>
      </Box> */}

      <StyledBox>
        <div className="card">
          <span>
            <h3>{statistics.data?.total_customers}</h3>
            <p>Overall Clients (GLOBAL)</p>
          </span>
          <button type="button">
            <img src={Arrow} alt="/" />
          </button>
        </div>
        <div className="card">
          <span>
          <h3>{statistics.data?.total_analysis}</h3>
            <p>Completed Consultation (GLOBAL)</p>
          </span>
          <button type="button">
            <img src={Arrow} alt="/" />
          </button>
        </div>
        <div className="card">
          <span>
          <h3>{formatNumber(statistics.data?.total_consultants|| 0) }</h3>
            <p>Number of BM (GLOBAL)</p>
          </span>
          <button type="button">
            <img src={Arrow} alt="/" />
          </button>
        </div>
        <div className="card">
          <span>
          <h3>{statistics.data?.total_stores}</h3>
            <p>Number of stores (GLOBAL)</p>
          </span>
          <button type="button">
            <img src={Arrow} alt="/" />
          </button>
        </div>
      </StyledBox>

      <StyledBox>
        <div className="table-chart-container">
          <header>
            <FormControl
              variant="outlined"
              style={{ minWidth: 150 }}
              size="small"
            >
              <InputLabel id="demo-simple-select-outlined-label">
                Sort By
              </InputLabel>
              <Select
                labelId="demo-simple-select-outlined-label"
                id="demo-simple-select-outlined"
                // value={user.app_id}
                // onChange={handleSwitchApp}
                label="Sort"
              >
                <MenuItem value="all">All</MenuItem>
                <MenuItem value="one month">One Month</MenuItem>
                <MenuItem value="two month">Two Month</MenuItem>
              </Select>
            </FormControl>
          </header>
          <Chart
            width={'100%'}
            height={'100%'}
            chartType="Bar"
            loader={<div>Loading Chart</div>}
            data={[
              [' ', ' ', ' '],
              ['Store 1', 1000, 400],
              ['Store 2', 1170, 460],
              ['Store 3', 660, 1120],
              ['Store 4', 1030, 540],
              ['Store 5', 1030, 540],
            ]}
            options={{
              // Material design options
              chart: {
                title: 'OVERALL PERFORMANCE',
                subtitle: 'Show the statistics',
              },
              hAxis: { ticks: [5, 10, 15, 20] },
            }}
            // For tests
            rootProps={{ 'data-testid': '2' }}
          />
        </div>

        <div className="line-chart-container">
          <header>
            <div className="line-chart-header-box">
              <h4>TIMEFRAME REPORT</h4>
              <p>
                Shows time-framed statistics for clients, consultations and
                generated QR code.
              </p>
            </div>
            <div className="line-chart-select-box">
              <FormControl
                className="form-control"
                variant="outlined"
                style={{ minWidth: 150 }}
                size="small"
              >
                <InputLabel id="demo-simple-select-outlined-label">
                  Time Frame
                </InputLabel>
                <Select
                  labelId="demo-simple-select-outlined-label"
                  id="demo-simple-select-outlined"
                  // value={user.app_id}
                  // onChange={handleSwitchApp}
                  label="Time Frame"
                >
                  <MenuItem value="all">All</MenuItem>
                  <MenuItem value="one month">One Month</MenuItem>
                  <MenuItem value="two month">Two Month</MenuItem>
                </Select>
              </FormControl>
              <Grid lg={12} md={12}>
                <DesktopDateRangePicker
                  clearable
                  value={[dateRange2.from, dateRange2.to]}
                  onChange={([from, to]) => {
                    if (from && to) {
                      setDateRange2({ from, to });
                    }
                  }}
                  renderInput={(startProps, endProps) => (
                    <>
                      <TextField
                        size="small"
                        // fullWidth
                        {...startProps}
                        variant="outlined"
                        helperText=""
                      />
                      <DateRangeDelimiter> ~ </DateRangeDelimiter>
                      <TextField
                        size="small"
                        // fullWidth
                        {...endProps}
                        variant="outlined"
                        helperText=""
                      />
                    </>
                  )}
                />
              </Grid>
            </div>
          </header>
